  function downloadFile(name, content, mime){
    const blob = new Blob([content], { type: mime });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = name; a.click();
    setTimeout(() => URL.revokeObjectURL(url), 1000);
  }
  function downloadCsv(){
    const rows = [['layer','title','mean','median','range','top_category']];
    (window.__aoi.conus_layers || []).forEach(r => {
      if(r.error){ rows.push([r.layer, r.title || '', '', '', '', r.error]); return; }
      if(r.top){
        const top = r.top.map(t => t.label + ' ' + t.pct + '%').join('; ');
        rows.push([r.layer, r.title, '', '', '', top]);
      } else {
        rows.push([r.layer, r.title, r.mean, r.median, (r.lo + ' - ' + r.hi), '']);
      }
    });
    const csv = rows.map(r => r.map(c => '"' + String(c).replace(/"/g, '""') + '"').join(',')).join('\\n');
    downloadFile('aoi_zonal_stats.csv', csv, 'text/csv');
  }
